public int repeatedNTimes(int[] nums) {
    Map<Integer, Integer> hashMap = new HashMap<>();
    for (int num : nums) {
        hashMap.put(num, hashMap.getOrDefault(num, 0) + 1);
        if (hashMap.get(num) > 1) return num;
    }
    return -1;
}
```


